package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_singleValue() throws IOException {
        String result = csvFormat.format("value");
        assertEquals("value", result);
    }

    @Test
    void testFormat_multipleValues() throws IOException {
        String result = csvFormat.format("value1", "value2", "value3");
        assertEquals("value1,value2,value3", result);
    }

    @Test
    void testFormat_nullValue() throws IOException {
        String result = csvFormat.format((Object) null);
        assertEquals("", result);
    }

    @Test
    void testFormat_emptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_withIOException() throws Exception {
        // Mock CSVPrinter to throw IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        // Use reflection to get the private constructor of CSVFormat
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class, Character.class, Character.class,
                boolean.class, boolean.class, String.class, String.class, Object[].class,
                String[].class, boolean.class, boolean.class, boolean.class, boolean.class,
                boolean.class, boolean.class);
        constructor.setAccessible(true);

        // Create a real CSVFormat instance with the same properties as DEFAULT
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        // Create a proxy CSVFormat that overrides the format method to use the mocked CSVPrinter
        CSVFormat csvFormatWithMock = new CSVFormat(
                baseFormat.getDelimiter(),
                baseFormat.getQuoteCharacter(),
                baseFormat.getQuoteMode(),
                baseFormat.getCommentMarker(),
                baseFormat.getEscapeCharacter(),
                baseFormat.getIgnoreSurroundingSpaces(),
                baseFormat.getIgnoreEmptyLines(),
                baseFormat.getRecordSeparator(),
                baseFormat.getNullString(),
                null,
                baseFormat.getHeader(),
                baseFormat.getSkipHeaderRecord(),
                baseFormat.getAllowMissingColumnNames(),
                baseFormat.getIgnoreHeaderCase(),
                baseFormat.getTrim(),
                baseFormat.getTrailingDelimiter(),
                baseFormat.getAutoFlush()) {
            @Override
            public String format(final Object... values) {
                final StringWriter out = new StringWriter();
                try (CSVPrinter printer = mockPrinter) {
                    mockPrinter.printRecord(values);
                    return out.toString().trim();
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatWithMock.format("value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
